void longestCommonPrefix(char strs[][MAXLEN], int n, char result[]) {
    if (n == 0) {
        strcpy(result, "");
        return;
    }

    strcpy(result, strs[0]);

    for (int i = 1; i < n; i++) {
        int j = 0;
        while (result[j] && strs[i][j] && result[j] == strs[i][j]) {
            j++;
        }
        result[j] = '\0';
        if (result[0] == '\0') {
            strcpy(result, "");
            return;
        }
    }
}

